map "http://ahdbservices.it/fhir/StructureMap/ControlsFirstOverviewToBundle" = "ControlsFirstOverviewToBundle"

uses "http://hl7.org/fhir/StructureDefinition/ControlsFirstOverview" alias ControlsFirstOverview as source
uses "http://hl7.org/fhir/StructureDefinition/Bundle" alias Bundle as target
uses "http://ahdbservices.it/fhir/StructureDefinition/PatientInput" alias PatientInput as source
uses "http://ahdbservices.it/fhir/StructureDefinition/MedicationInput" alias MedicationInput as source
uses "http://ahdbservices.it/fhir/StructureDefinition/ObservationDemographic" alias ObservationDemographic as source
uses "http://ahdbservices.it/fhir/StructureDefinition/ObservationSocial" alias ObservationSocial as source
uses "http://ahdbservices.it/fhir/StructureDefinition/ObservationSurvey" alias ObservationSurvey as source

imports "http://ahdbservices.it/fhir/StructureMap/QuestionnaireToQuestionnaireResponse"

group main(source src : ControlsFirstOverview, target bundle : Bundle) {
  src.patient as pt then {
    pt.subjectid as subjectId ->
        bundle.type = 'transaction',
        bundle.entry as e,
        e.request = create('BackboneElement') as req,
        req.method = 'POST',
        req.ifNoneExist = append('identifier=http://terminology.hl7.org/CodeSystem/v2-0203%7C', subjectId),
        req.url = 'Patient',
        e.resource = create('Patient') as patient,
        patient.id = uuid() as uuid,
        e.fullUrl = append('urn:uuid:', uuid) as pt_uri then {
          pt then PtToPatient(pt, patient) "Patient Input";

          src.research_time as efo ->
            bundle.entry as e1,
            e1.request = create('BackboneElement') as req,
            req.url = 'Practitioner',
            req.method = 'POST',
            e1.resource = create('Practitioner') as practitioner,
            practitioner.id = uuid() as uuid,
            practitioner.name = create('HumanName') as pn,
            pn.use = "usual",
            pn.family = "Aurelius",
            pn.given = "Marcus",
            pn.prefix = "Dr.",
            e1.fullUrl = append('urn:uuid:', uuid),

            bundle.entry as e,
            e.request = create('BackboneElement') as req,
            req.url = 'Encounter',
            req.method = 'POST',
            e.resource = create('Encounter') as encounter,
            encounter.id = uuid() as uuid,
            encounter.period = create('Period') as period,
            period.start = efo,
            encounter.serviceProvider = create ('Reference') as service,
            service.display = "WeargaitPD",
            encounter.status = "finished",
            encounter.class = create('Coding') as coding,
            coding.code = "AMB",
            coding.system = "http://terminology.hl7.org/ValueSet/v3-ActEncounterCode",
            coding.display = "ambulatory",
            encounter.subject = create('Reference') as subject,
            subject.reference = pt_uri,
            e.fullUrl = append('urn:uuid:', uuid) as enc_uri then {

              src.med as ms ->
                bundle.entry as e,
                e.request = create('BackboneElement') as req,
                req.url = 'MedicationStatement',
                req.method = 'POST',
                e.resource = create('MedicationStatement') as medicationstatement,
                medicationstatement.id = uuid() as uuid,
                e.fullUrl = append('urn:uuid:', uuid)
                then MedicationStatement(ms, patient, encounter, medicationstatement);

              src.obsdem as obs_dem ->
                bundle.entry as e,
                e.request = create('BackboneElement') as req,
                req.url = 'Observation',
                req.method = 'POST',
                e.resource = create('Observation') as observation,
                observation.id = uuid() as uuid,
                e.fullUrl = append('urn:uuid:', uuid) 
                then ObservationDem(obs_dem, patient, encounter, practitioner, observation);

              src.obssoc as obsso ->
                bundle.entry as e,
                e.request = create('BackboneElement') as req,
                req.url = 'Observation',
                req.method = 'POST',
                e.resource = create('Observation') as observation,
                observation.id = uuid() as uuid,
                e.fullUrl = append('urn:uuid:', uuid) 
                then ObservationSoc(obsso, patient, encounter, practitioner, observation);

              src.obssur as obssurv ->
                bundle.entry as e,
                e.request = create('BackboneElement') as req,
                req.url = 'Observation',
                req.method = 'POST',
                e.resource = create('Observation') as observation,
                observation.id = uuid() as uuid,
                e.fullUrl = append('urn:uuid:', uuid) 
                then ObservationSur(obssurv, patient, encounter, practitioner, observation);

              src.questmds as quest ->
                bundle.entry as e,
                e.request = create('BackboneElement') as req,
                req.url = 'QuestionnaireResponse',
                req.method = 'POST',
                e.resource = create('QuestionnaireResponse') as qr,
                qr.id = uuid() as uuid,
                e.fullUrl = append('urn:uuid:', uuid) 
                then QuestionnaireToQuestionnaireResponse(quest, patient, encounter, practitioner, qr);
            };
        };
  };
}

group PtToPatient(
  source pt : PatientInput,
  target patient : Patient
) {
    pt.sex where $this = 'Male' -> patient.gender = 'male';
    pt.sex where $this = 'Female' -> patient.gender = 'female';
    pt.subjectid as subjectId ->
      patient.identifier as i,
      i.value = subjectId,
      i.system = "http://terminology.hl7.org/CodeSystem/v2-0203";
}

group MedicationStatement(
  source ms : MedicationInput,
  source patient : Patient,
  source encounter : Encounter,
  target medicationstatement : MedicationStatement
) {
    ms.currentmedications as cmd -> 
      medicationstatement.status = "active",
      medicationstatement.medication = create('CodeableConcept') as mcc,
      mcc.coding = create('Coding') as coding,
      coding.code = "104205-0",
      coding.system = "http://loinc.org",
      coding.display = "Patient generated medication list",
      mcc.text = cmd;

    patient.id as p_id ->
      medicationstatement.subject = create('Reference') as subj,
      subj.reference = append("urn:uuid:", p_id);

    encounter.id as enc_id ->
      medicationstatement.context = create('Reference') as cont,
      cont.reference = append("urn:uuid:", enc_id);
}

group ObservationDem(
  source do : ObservationDemographic,
  source patient : Patient,
  source encounter : Encounter,
  source practitioner : Practitioner,
  target observation : Observation
) {
    do -> observation.status = "registered" "Observation status";

    do -> observation.category = create('CodeableConcept') as cc,
        cc.text = "Vital Signs",
        cc.coding = create('Coding') as coding,
        coding.code = "vital-signs",
        coding.system = "http://terminology.hl7.org/CodeSystem/observation-category",
        coding.display = "Vital Signs" "Vital signs mapping";

    do.weight as w ->
      observation.component as oc,
      oc.code = create('CodeableConcept') as cc,
      cc.coding as coding,
      coding.code = "29463-7",
      coding.system = "http://loinc.org",
      coding.display = "Body Weight",
        
      oc.value = create('Quantity') as q,
      q.value = w,
      q.system = "http://unitsofmeasure.org",
      q.code = "kg",
      q.unit = "kg";

    do.height as h ->
      observation.component as oc,
      oc.code = create('CodeableConcept') as cc,
      cc.coding as coding,
      coding.code = "8302-2",
      coding.system = "http://loinc.org",
      coding.display = "Body Height",
        
      oc.value = create('Quantity') as q,
      q.value = h,
      q.system = "http://unitsofmeasure.org",
      q.code = "[in_i]",
      q.unit = "in";

    do.age as age ->
      observation.component as oc,
      oc.code = create('CodeableConcept') as cc,
      cc.coding as coding,
      coding.code = "63900-5",
      coding.system = "http://loinc.org",
      coding.display = "Age",
        
      oc.value = create('Quantity') as q,
      q.value = age,
      q.system = "http://unitsofmeasure.org",
      q.code = "a",
      q.unit = "years";

    patient.id as p_id ->
      observation.subject = create('Reference') as subj,
      subj.reference = append("urn:uuid:", p_id);

    encounter.id as enc_id ->
      observation.encounter = create('Reference') as cont,
      cont.reference = append("urn:uuid:", enc_id);

    practitioner.id as prac_id ->
      observation.performer = create('Reference') as perf,
      perf.reference = append("urn:uuid:", prac_id);
}

group ObservationSoc(
  source so : ObservationSocial,
  source patient : Patient,
  source encounter : Encounter,
  source practitioner : Practitioner,
  target observation : Observation
) {
    so -> observation.status = "registered" "Observation status";

    so -> observation.category = create('CodeableConcept') as cc,
        cc.text = "Social History",
        cc.coding = create('Coding') as coding,
        coding.code = "social-history",
        coding.system = "http://terminology.hl7.org/CodeSystem/observation-category",
        coding.display = "Social History" "Social History Observation";

    so.pt_ot_status as ptst ->
      observation.component as oc,
      oc.code = create('CodeableConcept') as cc,
      cc.coding as coding,
      coding.code = "localptotstatus",
      coding.system = "http://ahdbservices.it/fhir/CodeSystem/LocalProjectCode",
      coding.display = "Local PT-OT Status",
        
      oc.value = create('CodeableConcept') as q,
      q.text = ptst;

    so.frequency_pt_ot as ptf ->
      observation.component as oc,
      oc.code = create('CodeableConcept') as cc,
      cc.coding as coding,
      coding.code = "localptotfrequency",
      coding.system = "http://ahdbservices.it/fhir/CodeSystem/LocalProjectCode",
      coding.display = "Local PT-OT Frequency",
        
      oc.value = create('CodeableConcept') as q,
      q.text = ptf;

    patient.id as p_id ->
      observation.subject = create('Reference') as subj,
      subj.reference = append("urn:uuid:", p_id);

    encounter.id as enc_id ->
      observation.encounter = create('Reference') as cont,
      cont.reference = append("urn:uuid:", enc_id);

    practitioner.id as prac_id ->
      observation.performer = create('Reference') as perf,
      perf.reference = append("urn:uuid:", prac_id);
}

group ObservationSur(
  source sur : ObservationSurvey,
  source patient : Patient,
  source encounter : Encounter,
  source practitioner : Practitioner,
  target observation : Observation
) {
    sur -> observation.status = "registered" "Observation status";

    sur -> observation.category = create('CodeableConcept') as cc,
        cc.text = "Survey",
        cc.coding = create('Coding') as coding,
        coding.code = "survey",
        coding.system = "http://terminology.hl7.org/CodeSystem/observation-category",
        coding.display = "Survey" "Survey Observation";

    sur.moca_score as moc ->
      observation.component as oc,
      oc.code = create('CodeableConcept') as cc,
      cc.coding as coding,
      coding.code = "72172-0",
      coding.system = "http://loinc.org",
      coding.display = "Total score [MoCA]",
        
      oc.value = create('Quantity') as q,
      q.value = moc,
      q.system = "http://unitsofmeasure.org",
      q.code = "{score}",
      q.unit = "{score}";

    patient.id as p_id ->
      observation.subject = create('Reference') as subj,
      subj.reference = append("urn:uuid:", p_id);

    encounter.id as enc_id ->
      observation.encounter = create('Reference') as cont,
      cont.reference = append("urn:uuid:", enc_id);

    practitioner.id as prac_id ->
      observation.performer = create('Reference') as perf,
      perf.reference = append("urn:uuid:", prac_id);
}